mapper.select:
SELECT id, country, country_name AS countryName, category, import_tax_rate AS importTaxRate, vat_rate AS vatRate, consumption_tax_rate AS consumptionTaxRate, effective_tax_rate AS effectiveTaxRate, hs_code AS hsCode, description, policy_changes AS policyChanges, tax_tips AS taxTips, create_time AS createTime, update_time AS updateTime FROM tax_rates
AND country = #{country}
AND category = #{category}
LIMIT 1
